const i=[{id:"file",name:"文件管理",icon:"FolderOpenOutlined",description:"文件和目录的增删改查",commandCount:25},{id:"process",name:"进程管理",icon:"ControlOutlined",description:"进程查看、终止、优先级",commandCount:12},{id:"network",name:"网络工具",icon:"WifiOutlined",description:"网络诊断、端口、连接",commandCount:18},{id:"text",name:"文本处理",icon:"FileTextOutlined",description:"grep/awk/sed三剑客",commandCount:20},{id:"user",name:"用户权限",icon:"UserOutlined",description:"用户、组、权限管理",commandCount:10},{id:"system",name:"系统状态",icon:"DashboardOutlined",description:"系统信息、资源监控",commandCount:10},{id:"package",name:"软件包",icon:"InboxOutlined",description:"yum/apt/dnf/rpm",commandCount:8},{id:"disk",name:"磁盘管理",icon:"HddOutlined",description:"磁盘分区、挂载、备份",commandCount:8}],e=[{id:"ls",name:"ls",categoryId:"file",description:"列出目录内容，是Linux中最常用的命令之一",syntax:"ls [选项] [文件/目录...]",level:"beginner",options:[{flag:"-l",description:"长格式显示，显示详细信息"},{flag:"-a",description:"显示所有文件，包括隐藏文件"},{flag:"-h",description:"以人类可读的格式显示大小（K/M/G）"},{flag:"-t",description:"按修改时间排序（最新在前）"},{flag:"-r",description:"反向排序"},{flag:"-R",description:"递归显示子目录"},{flag:"-i",description:"显示inode号"},{flag:"-S",description:"按文件大小排序"},{flag:"-d",description:"只显示目录本身，不显示内容"}],combinations:["ls -lah    # 显示所有文件的详细信息（含隐藏）","ls -lht    # 按修改时间排序，最新在前","ls -ltr    # 按修改时间排序，最旧在前","ls -lhS    # 按文件大小从大到小排序","ls -i      # 显示文件inode号"],examples:[{title:"查看当前目录的文件",code:"ls -lah",output:`total 24K
drwxr-xr-x  3 root root 4.0K Jun 30 10:00 .
drwxr-xr-x  1 root root 4.0K Jun 28 09:00 ..
-rw-r--r--  1 root root  123 Jun 30 09:30 test.txt
drwxr-xr-x  2 root root 4.0K Jun 30 09:59 docs`},{title:"查看指定目录",code:"ls -lh /var/log/"},{title:"配合grep筛选",code:'ls -la | grep ".conf"'}],tips:'ll 是 ls -l 的别名，几乎每个运维都在用。可以在 .bashrc 中设置 alias ll="ls -l --color=auto"。配合通配符使用更灵活：ls *.log 查看所有日志文件。'},{id:"cd",name:"cd",categoryId:"file",description:"切换当前工作目录",syntax:"cd [目录路径]",level:"beginner",options:[],combinations:["cd /       # 切换到根目录","cd ~       # 切换到家目录","cd -       # 回到上一次的目录","cd ..      # 回到上级目录","cd ../..   # 回到上两级目录"],examples:[{title:"切换到/etc目录",code:"cd /etc"},{title:"回到家目录",code:"cd ~"},{title:"快速返回上一个目录",code:"cd -"}],tips:"cd 不加任何参数等价于 cd ~，都会回到当前用户的家目录。cd - 可以在两个目录之间快速切换，非常实用。"},{id:"pwd",name:"pwd",categoryId:"file",description:"显示当前工作目录的完整路径",syntax:"pwd",level:"beginner",options:[{flag:"-P",description:"显示物理路径，不显示软链接"}],combinations:[],examples:[{title:"查看当前目录",code:"pwd",output:"/etc/nginx"},{title:"查看物理路径（去软链接）",code:"pwd -P"}],tips:"当你在一个很深的目录里迷路时，pwd 能帮你定位当前位置。在写脚本时，pwd 常用来获取当前目录路径赋值给变量。"},{id:"mkdir",name:"mkdir",categoryId:"file",description:"创建新目录",syntax:"mkdir [选项] 目录名...",level:"beginner",options:[{flag:"-p",description:"递归创建多级目录，父目录不存在时自动创建"},{flag:"-m",description:"创建目录时指定权限"},{flag:"-v",description:"显示创建过程"}],combinations:["mkdir -p a/b/c/d    # 创建多级目录","mkdir -m 755 dir    # 创建时设置权限","mkdir dir{1..5}     # 批量创建dir1到dir5"],examples:[{title:"创建单个目录",code:"mkdir test"},{title:"创建多级目录",code:"mkdir -p project/src/utils"},{title:"批量创建",code:"mkdir log backup data temp"}],tips:"花括号展开非常好用：mkdir -p /data/{app,log,backup,config} 可以一次性创建多个子目录。"},{id:"rm",name:"rm",categoryId:"file",description:"删除文件或目录（危险命令，请谨慎使用）",syntax:"rm [选项] 文件/目录...",level:"beginner",options:[{flag:"-r",description:"递归删除，删除目录及其内容"},{flag:"-f",description:"强制删除，不提示确认"},{flag:"-i",description:"删除前提示确认"},{flag:"-v",description:"显示删除过程"}],combinations:["rm -rf dir/        # 强制递归删除目录（慎用！）","rm -i *.log        # 删除前逐个确认","rm -f *.tmp        # 强制删除临时文件"],examples:[{title:"删除单个文件",code:"rm test.txt"},{title:"删除目录",code:"rm -rf old_project/"},{title:"删除前确认",code:"rm -i *.bak"}],tips:'⚠️ rm -rf / 绝对不要运行！生产环境建议 alias rm="rm -i" 开启交互确认，或使用 trash-cli 替代 rm，实现回收站效果。删除前先用 ls 确认要删的文件。'},{id:"cp",name:"cp",categoryId:"file",description:"复制文件或目录",syntax:"cp [选项] 源文件 目标文件",level:"beginner",options:[{flag:"-r",description:"递归复制目录"},{flag:"-p",description:"保留文件属性（权限、时间戳等）"},{flag:"-a",description:"归档复制，等价于 -dr --preserve=all"},{flag:"-f",description:"强制覆盖，不提示"},{flag:"-i",description:"覆盖前提示"},{flag:"-v",description:"显示复制过程"},{flag:"-u",description:"只复制源文件比目标新的文件"}],combinations:["cp -a dir1 dir2      # 完整复制目录（保留所有属性）","cp -rv src/ dest/    # 递归复制并显示过程","cp -u *.txt backup/  # 只复制更新过的文件"],examples:[{title:"复制文件",code:"cp file.txt file_copy.txt"},{title:"复制目录",code:"cp -r project/ project_backup/"},{title:"保留属性复制",code:"cp -p config.conf config.conf.bak"}],tips:"备份配置文件时推荐用 cp -p 保留原时间戳，方便排查问题。复制大量小文件时，用 cp -a 比 cp -r 更完整。"},{id:"mv",name:"mv",categoryId:"file",description:"移动文件或目录，也可用于重命名",syntax:"mv [选项] 源文件 目标文件",level:"beginner",options:[{flag:"-f",description:"强制覆盖，不提示"},{flag:"-i",description:"覆盖前提示"},{flag:"-u",description:"只移动源文件比目标新的文件"},{flag:"-v",description:"显示移动过程"}],combinations:["mv file.txt /tmp/       # 移动文件","mv oldname newname      # 重命名","mv -v dir1/ dir2/       # 移动并显示过程"],examples:[{title:"重命名文件",code:"mv old.txt new.txt"},{title:"移动多个文件",code:"mv *.log /var/log/backup/"},{title:"安全移动（有提示）",code:"mv -i data.csv /data/"}],tips:"mv 既可以移动也可以重命名，取决于目标是目录还是文件。如果目标是已存在的目录，源会被移到里面；否则就是重命名。"},{id:"find",name:"find",categoryId:"file",description:"在指定目录下查找文件和目录，功能非常强大",syntax:"find [路径] [表达式]",level:"intermediate",options:[{flag:"-name",description:"按文件名查找（支持通配符）"},{flag:"-iname",description:"按文件名查找（忽略大小写）"},{flag:"-type",description:"按类型查找（f文件/d目录/l链接）"},{flag:"-size",description:"按大小查找（+10M大于10M，-100K小于100K）"},{flag:"-mtime",description:"按修改时间查找（+7七天前，-1一天内）"},{flag:"-mmin",description:"按修改分钟数查找"},{flag:"-user",description:"按所有者查找"},{flag:"-perm",description:"按权限查找"},{flag:"-exec",description:"对找到的文件执行命令"},{flag:"-delete",description:"删除找到的文件"}],combinations:['find /etc -name "*.conf"           # 查找配置文件',"find /var -type f -size +100M      # 找大于100M的文件","find /tmp -mtime +7 -delete        # 删除7天前的临时文件",'find . -name "*.log" -exec rm {} \\;  # 批量删除日志',"find / -perm -4000 -type f         # 查找有SUID的文件"],examples:[{title:"按名称查找配置文件",code:'find /etc -name "nginx*.conf"'},{title:"找大文件",code:"find / -type f -size +500M 2>/dev/null"},{title:"批量改权限",code:"find /var/www -type f -exec chmod 644 {} \\;"}],tips:"find 是运维神器，掌握了能大大提高效率。-exec 后面的 {} 代表找到的文件，注意结尾的 \\; 不能少。查找大文件时加上 2>/dev/null 可以屏蔽权限错误。"},{id:"grep",name:"grep",categoryId:"text",description:"在文件中搜索匹配的字符串，文本处理三剑客之首",syntax:"grep [选项] 模式 [文件...]",level:"beginner",options:[{flag:"-i",description:"忽略大小写"},{flag:"-v",description:"反向匹配，显示不匹配的行"},{flag:"-n",description:"显示行号"},{flag:"-r",description:"递归搜索目录"},{flag:"-l",description:"只显示包含匹配的文件名"},{flag:"-c",description:"统计匹配的行数"},{flag:"-o",description:"只输出匹配的部分"},{flag:"-A n",description:"显示匹配行及后面n行"},{flag:"-B n",description:"显示匹配行及前面n行"},{flag:"-C n",description:"显示匹配行及前后n行"},{flag:"-E",description:"使用扩展正则表达式（同egrep）"}],combinations:['grep -rn "error" /var/log/        # 递归搜索error','grep -v "^#" nginx.conf           # 过滤注释行','grep -c "GET" access.log          # 统计GET请求数',"ps aux | grep nginx               # 查找进程",'grep -E "(error|fail)" log.txt    # 多关键字匹配'],examples:[{title:"在日志中找错误",code:'grep -i "error" app.log'},{title:"显示匹配行的上下文",code:'grep -C 3 "exception" error.log'},{title:"过滤空行和注释",code:'grep -vE "^$|^#" nginx.conf'}],tips:"grep 是日常使用频率最高的命令之一。结合管道符 | 可以和其他命令配合使用。-E 扩展正则支持 | 或运算、+ 等，非常实用。"},{id:"ps",name:"ps",categoryId:"process",description:"查看当前系统中的进程状态",syntax:"ps [选项]",level:"beginner",options:[{flag:"a",description:"显示所有终端的进程"},{flag:"u",description:"显示用户和资源使用情况"},{flag:"x",description:"显示没有终端的进程"},{flag:"-e",description:"显示所有进程"},{flag:"-f",description:"显示完整格式（UID, PPID等）"},{flag:"-o",description:"自定义输出字段"}],combinations:["ps aux                   # 显示所有进程（BSD风格）","ps -ef                   # 显示所有进程（System V风格）","ps -u root               # 只看root用户的进程","ps aux | grep nginx      # 查找nginx进程","ps -eo pid,ppid,cmd,%mem,%cpu --sort=-%mem | head  # 按内存排序"],examples:[{title:"查看所有进程",code:"ps aux"},{title:"找特定进程",code:"ps -ef | grep sshd"},{title:"看进程树",code:"ps auxf"}],tips:"ps aux 和 ps -ef 都是常用组合，一个是 BSD 风格一个是 System V 风格，效果类似。看进程树用 pstree 更直观。"},{id:"kill",name:"kill",categoryId:"process",description:"向进程发送信号，通常用来终止进程",syntax:"kill [选项] PID...",level:"beginner",options:[{flag:"-l",description:"列出所有可用信号"},{flag:"-9",description:"SIGKILL，强制杀死进程"},{flag:"-15",description:"SIGTERM，优雅终止（默认）"},{flag:"-1",description:"SIGHUP，重启进程"},{flag:"-2",description:"SIGINT，同Ctrl+C"}],combinations:["kill 1234                # 默认TERM信号终止","kill -9 1234             # 强制杀死","kill -HUP 1234           # 重启进程（重新加载配置）","killall nginx            # 按名称杀所有nginx进程",'pkill -f "python app.py" # 按命令模式杀进程'],examples:[{title:"优雅终止进程",code:"kill 5678"},{title:"强制杀死挂死的进程",code:"kill -9 5678"},{title:"让nginx重新加载配置",code:"kill -HUP $(cat /var/run/nginx.pid)"}],tips:"⚠️ kill -9 是最后手段，进程无法处理这个信号会被立即终止，可能导致数据丢失。优先用默认的 kill -15 (SIGTERM) 让进程优雅退出。"},{id:"top",name:"top",categoryId:"process",description:"实时动态显示系统进程和资源使用情况",syntax:"top [选项]",level:"beginner",options:[{flag:"-d",description:"指定刷新间隔（秒）"},{flag:"-p",description:"只监控指定PID的进程"},{flag:"-u",description:"只显示指定用户的进程"},{flag:"-n",description:"刷新n次后退出"},{flag:"-b",description:"批处理模式，可输出到文件"}],combinations:["top                      # 启动top","top -u nginx             # 只看nginx进程","top -p 1234,5678         # 只监控指定进程","top -b -n 1 > top.log    # 输出一次结果到文件"],examples:[{title:"查看系统整体负载",code:"top"},{title:"每5秒刷新一次",code:"top -d 5"}],tips:"top 交互快捷键：P 按CPU排序、M 按内存排序、T 按时间排序、1 显示多核、k 杀进程、q 退出。也可以用更友好的 htop。"},{id:"chmod",name:"chmod",categoryId:"user",description:"修改文件或目录的权限",syntax:"chmod [选项] 权限 文件...",level:"beginner",options:[{flag:"-R",description:"递归修改目录及其内容"},{flag:"-v",description:"显示修改过程"},{flag:"-c",description:"只显示有修改的"}],combinations:["chmod 755 file.sh           # rwxr-xr-x","chmod 644 file.txt          # rw-r--r--","chmod +x script.sh          # 加执行权限","chmod -R 755 /var/www       # 递归修改","chmod u+x,g-w,o+r file      # 符号方式"],examples:[{title:"给脚本加执行权限",code:"chmod +x deploy.sh"},{title:"设置目录权限",code:"chmod 750 /data/private/"},{title:"递归修改目录权限",code:"find /var/www -type d -exec chmod 755 {} \\;"}],tips:"权限数字速记：r=4, w=2, x=1。常用组合：文件 644，目录 755，可执行文件 755，私密文件 600。"},{id:"chown",name:"chown",categoryId:"user",description:"修改文件或目录的所有者和所属组",syntax:"chown [选项] 用户[:组] 文件...",level:"beginner",options:[{flag:"-R",description:"递归修改"},{flag:"-v",description:"显示修改过程"}],combinations:["chown nginx file.conf       # 修改所有者","chown nginx:devops file     # 修改所有者和组","chown -R app:app /data/app  # 递归修改","chown :wheel file           # 只修改组"],examples:[{title:"修改文件所有者",code:"chown www-data index.html"},{title:"递归修改目录",code:"chown -R nginx:nginx /var/www/html"}],tips:"chown 需要 root 权限。也可以用 chgrp 单独修改组。部署网站时，确保 Web 服务器用户对文件有正确的权限。"},{id:"df",name:"df",categoryId:"disk",description:"查看磁盘分区使用情况",syntax:"df [选项] [文件...]",level:"beginner",options:[{flag:"-h",description:"人类可读的单位（K/M/G）"},{flag:"-i",description:"显示inode使用情况"},{flag:"-T",description:"显示文件系统类型"},{flag:"-t",description:"只显示指定类型的文件系统"}],combinations:["df -h                     # 查看磁盘使用","df -ih                    # 查看inode使用","df -T                     # 查看文件系统类型","df -h /data               # 只看某个分区"],examples:[{title:"查看整体磁盘使用",code:"df -h"},{title:"排查inode耗尽",code:"df -ih"}],tips:"磁盘满了分两种：空间满了和 inode 满了。inode 满通常是因为小文件太多。df -h 看空间，df -i 看 inode。"},{id:"du",name:"du",categoryId:"disk",description:"查看文件或目录占用的磁盘空间",syntax:"du [选项] [文件...]",level:"beginner",options:[{flag:"-h",description:"人类可读的单位"},{flag:"-s",description:"只显示总计"},{flag:"-a",description:"显示所有文件大小"},{flag:"-c",description:"显示总计"},{flag:"--max-depth=N",description:"显示的目录深度"}],combinations:["du -sh /var/log/          # 查看目录总大小","du -h --max-depth=1 /data # 查看一级子目录大小","du -sh * | sort -rh       # 当前目录按大小排序","du -ah | sort -rh | head  # 找最大的文件"],examples:[{title:"查看目录大小",code:"du -sh /home/"},{title:"找占用空间最大的目录",code:"du -h --max-depth=1 / | sort -rh | head -10"}],tips:"du 统计的是实际占用空间，和 ls 显示的文件大小可能不同（稀疏文件、块大小等原因）。排查磁盘满了用 du 逐层找大文件。"},{id:"netstat",name:"netstat",categoryId:"network",description:"查看网络连接、路由表、端口监听等网络状态",syntax:"netstat [选项]",level:"beginner",options:[{flag:"-t",description:"显示TCP连接"},{flag:"-u",description:"显示UDP连接"},{flag:"-l",description:"显示监听中的端口"},{flag:"-n",description:"数字形式显示地址和端口"},{flag:"-p",description:"显示进程名和PID"},{flag:"-a",description:"显示所有连接和监听端口"},{flag:"-r",description:"显示路由表"},{flag:"-s",description:"显示统计信息"}],combinations:["netstat -tlnp              # 查看监听的TCP端口","netstat -anp               # 查看所有网络连接","netstat -nat | grep 80     # 看80端口的连接","netstat -rn                # 查看路由表","netstat -s                 # 网络协议统计"],examples:[{title:"查看所有监听端口",code:"netstat -tlnp"},{title:"统计连接状态",code:"netstat -n | awk '/^tcp/ {++S[$NF]} END {for(a in S) print a, S[a]}'"}],tips:"netstat 在新系统中逐渐被 ss 命令取代，ss 更快更高效。但 netstat 还是运维必须掌握的经典命令。"},{id:"curl",name:"curl",categoryId:"network",description:"命令行数据传输工具，常用于发送HTTP请求",syntax:"curl [选项] URL",level:"intermediate",options:[{flag:"-I",description:"只获取响应头"},{flag:"-v",description:"显示详细过程"},{flag:"-X",description:"指定请求方法（GET/POST/PUT等）"},{flag:"-d",description:"POST数据"},{flag:"-H",description:"自定义请求头"},{flag:"-o",description:"保存到文件"},{flag:"-O",description:"用远程文件名保存"},{flag:"-s",description:"静默模式，不输出进度"},{flag:"-u",description:"用户名:密码 认证"},{flag:"-L",description:"跟随重定向"},{flag:"-k",description:"忽略SSL证书错误"}],combinations:["curl http://example.com        # GET请求","curl -I http://example.com     # 只看响应头",'curl -X POST -d "a=1&b=2" url  # POST表单','curl -H "Authorization: Bearer xxx" url  # 带Token',"curl -o file.zip url           # 下载文件","curl -sSL url | bash           # 下载并执行脚本"],examples:[{title:"测试网站是否可访问",code:"curl -I -s https://baidu.com | head -5"},{title:"发送JSON数据",code:`curl -X POST -H "Content-Type: application/json" -d '{"name":"test"}' https://api.example.com`}],tips:"curl 是调试 Web 接口的神器。-v 参数可以看到完整的请求和响应过程，排障时非常有用。-w 参数可以自定义输出格式，打印响应时间等。"},{id:"ping",name:"ping",categoryId:"network",description:"测试主机之间的网络连通性",syntax:"ping [选项] 目标地址",level:"beginner",options:[{flag:"-c",description:"发送指定数量的包后停止"},{flag:"-i",description:"发送间隔时间（秒）"},{flag:"-s",description:"指定数据包大小"},{flag:"-t",description:"持续ping（Windows）"},{flag:"-W",description:"超时时间（秒）"}],combinations:["ping baidu.com              # 持续ping","ping -c 4 baidu.com         # 发4个包","ping -c 10 -i 0.5 192.168.1.1  # 间隔0.5秒","ping -s 1000 baidu.com      # 1000字节大包"],examples:[{title:"测试网络通不通",code:"ping -c 4 8.8.8.8"},{title:"测试延迟",code:"ping -c 100 baidu.com | tail -5"}],tips:"ping 通 ≠ 服务可用，只能说明网络层连通。端口和服务是否正常还要用 telnet/nc/curl 进一步确认。ping 不通也可能是防火墙禁了ICMP。"}];export{e as a,i as c};
